mapper.select:
SELECT COUNT(*) FROM hm_query.dim_product
WHERE product_status = 'PUBLISHED'
AND category_id = #{categoryId}
AND brand = #{brand}
AND (product_name ILIKE CONCAT('%', #{q}, '%') OR description ILIKE CONCAT('%', #{q}, '%') OR brand ILIKE CONCAT('%', #{q}, '%'))
AND product_id = #{id}

SELECT COUNT(*) FROM hm_query.order_details_flat
WHERE tenant = #{tenant}
AND customer_id = #{customerId}

SELECT COUNT(*) FROM hm_query.order_details_flat
WHERE tenant = #{tenant}
AND customer_id = #{customerId}

SELECT COUNT(*) FROM hm_query.review_flat
WHERE review_status = 'PUBLISHED' AND product_id = #{productId}
AND rating = #{rating}

SELECT COUNT(*)
FROM hm_query.notification_flat

    AND customer_id = #{customerId}
    AND type = #{type}
    AND title ILIKE CONCAT('%', #{title}, '%')
    AND is_read = CAST(#{isRead} AS boolean)
    AND created_time BETWEEN #{createdTime[0]} AND #{createdTime[1]}

SELECT cn.notification_id as "id", cn.type as "type", cn.title as "title", cn.message as "message", cn.is_read as "isRead", cn.reference_id as "referenceId", cn.reference_type as "referenceType", cn.created_time as "createdTime" FROM hm_query.notification_flat cn
AND cn.customer_id = #{customerId} AND cn.type = #{type} AND cn.title ILIKE CONCAT('%', #{title}, '%') AND cn.is_read = CAST(#{isRead} AS boolean) AND cn.created_time BETWEEN #{createdTime[0]} AND #{createdTime[1]}
${orderby} ${pagination}
